"import re\nimport urllib.request\nimport ssl\n\nctx = ssl.create_default_context()\nctx.check_hostname = False\nctx.verify_mode = ssl.CERT_NONE\n\ndef test_file_images(filepath):\n    print(f\"\\n=== Testing images in {filepath} ===\")\n    with open(filepath, 'r', encoding='utf-8') as f:\n        content = f.read()\n\n    image_urls = re.findall(r'<img[^>]+src=[\"\\']([^\"\\']+)[\"\\']', content)\n    print(f\"Found {len(image_urls)} images.\")\n    for i, url in enumerate(image_urls):\n        if url.startswith('http'):\n            try:\n                req = urllib.request.Request(\n                    url, \n                    headers={'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/58.0.3029.110 Safari/537.3'}\n                )\n                with urllib.request.urlopen(req, context=ctx, timeout=5) as response:\n                    status = response.status\n                print(f\"[{i+1}/{len(image_urls)}] {status} - {url[:60]}...\")\n            except Exception as e:\n                print(f\"[{i+1}/{len(image_urls)}] FAILED: {e} - {url[:60]}...\")\n        else:\n            print(f\"[{i+1}/{len(image_urls)}] LOCAL PATH - {url}\")\n\ntest_file_images('templates/mobilephone.html')\ntest_file_images('index.html')\n"